using Microsoft.EntityFrameworkCore; using Microsoft.Extensions.Configuration; using Microsoft.Extensions.DependencyInjection; using ModularMonolith.Modules.Users.Application; using ModularMonolith.Modules.Users.Contracts; using ModularMonolith.Modules.Users.Infrastructure;
namespace ModularMonolith.Modules.Users;
public static class UsersModule { public static IMvcBuilder AddUsersModule(this IMvcBuilder mvc,IConfiguration cfg){ mvc.Services.AddDbContext<UsersDbContext>(o=>o.UseSqlite(cfg.GetConnectionString("Users")??"Data Source=modular-monolith.db")); mvc.Services.AddScoped<UsersService>(); mvc.Services.AddScoped<IUsersModule>(sp=>sp.GetRequiredService<UsersService>()); mvc.AddApplicationPart(typeof(UsersModule).Assembly); return mvc; } public static async Task SeedUsersAsync(this IServiceProvider sp){ using var s=sp.CreateScope(); var db=s.ServiceProvider.GetRequiredService<UsersDbContext>(); await db.Database.EnsureCreatedAsync(); if(await db.Users.AnyAsync())return; var a=Domain.User.Create("Ada","Lovelace","ada@example.com"); var b=Domain.User.Create("Grace","Hopper","grace@example.com"); var c=Domain.User.Create("Inactive","User","inactive@example.com"); c.Deactivate(); db.Users.AddRange(a,b,c); await db.SaveChangesAsync(); }}
